import React, { useState } from 'react';
import { View, Button, Alert, Platform } from 'react-native';
import * as InAppPurchases from 'expo-in-app-purchases'; // Use Expo's In-App-Purchases module
import { useEffect } from 'react';
import { Payment } from 'react-native-payments'; // For digital wallets

const PaymentModule = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    initiatePurchaseSetup();

    return () => {
      InAppPurchases.disconnectAsync();
    };
  }, []);

  const initiatePurchaseSetup = async () => {
    const response = await InAppPurchases.connectAsync();
    if (response.results) {
      setProducts(response.results);
    }
  };

  const handlePurchase = async (productId) => {
    try {
      const { responseCode, results } = await InAppPurchases.purchaseItemAsync(productId);
      if(responseCode === InAppPurchases.IAPResponseCode.OK) {
        Alert.alert('Purchase successful', `Product: ${results[0].productId}`);
      }
    } catch (error) {
      Alert.alert('Purchase failed', error.message);
    }
  };

  const initiatePaymentRequest = async () => {
    const methodData = [{ supportedMethods: ['apple-pay', 'google-pay'] }];
    const details = {
      displayItems: [
        { label: 'Item', amount: { currency: 'USD', value: '1.00' } }
      ],
      total: { label: 'Total', amount: { currency: 'USD', value: '1.00' } }
    };

    try {
      const paymentRequest = new PaymentRequest(methodData, details);
      const paymentResponse = await paymentRequest.show();

      await paymentResponse.complete('success');
      Alert.alert('Payment successful', 'Thank you for your purchase');
    } catch (error) {
      Alert.alert('Payment failed', error.message);
    }
  };

  return (
    <View>
      {products.map((product, index) => (
        <Button key={index} title={`Buy ${product.title}`} onPress={() => handlePurchase(product.productId)} />
      ))}
      <Button title="Pay with Digital Wallet" onPress={initiatePaymentRequest} />
    </View>
  );
};

export default PaymentModule;